// 1. Capture the raw input
const input = $input.first().json;

// 2. Extract data directly or parse if it's a string
let data;
try {
  // AI Agents sometimes wrap arguments in a 'query' or 'arguments' string
  const rawData = input.arguments || input.query || input;
  data = typeof rawData === 'string' ? JSON.parse(rawData) : rawData;
} catch (e) {
  data = input;
}

// 3. Map and Clean variables for the SQL Query
return {
  doctor_id: data.doctor_id || "MISSING_ID",

  // Support both possible naming conventions from the AI
  start_time: data.start_date_time || data.start_time || "MISSING_TIME",

  patient_name: (data.patient_name || "Unknown Patient").replace(/'/g, "''"),

  // Sanitize phone: Keep only digits
  patient_phone: data.patient_phone ? String(data.patient_phone).replace(/\D/g, "") : "MISSING_PHONE",

  // Map "reason" to "note" for the database
  note: data.reason || "No reason provided"
};

// 1. Capture the results from the Postgres Node
const bookingData = $input.first().json;

// 2. Prepare the payload for the AI Agent
return {
  status: "success",
  confirmation_body: {
    message: "تم تسجيل الموعد بنجاح ",
    patient: $('Code in JavaScript').first().json.patient_name || "Unknown",
    time: $('Code in JavaScript').first().json.start_time || "Not specified",
  },
  // This instruction tells the AI exactly how to phrase the response
  instruction_for_ai: "Confirm the appointment details to the patient in professional Moroccan Darija. Be welcoming and mention the specific time."
};
